import { useEffect, useState } from "react";

export default function ClubMembers({ clubId }) {
    const [members, setMembers] = useState([]);

    useEffect(() => {
        fetch(`/api/clubs/${clubId}/members`)
            .then(r => r.json())
            .then(setMembers);
    }, [clubId]);

    return (
        <div className="card">
            <h3>Members</h3>
            {members.map(m => (
                <div key={m.id}>
                    User #{m.userId} — {m.role}
                </div>
            ))}
        </div>
    );
}
